type PredicateRegistration = {
    predicateTrait: TagTrait;
    dependencyTraits: Trait[];
    predicateFn: (data: unknown[]) => unknown;
};

/** IDs of every hidden tag trait created by createPredicate, across all predicates. */
const predicateTraitIds = new Set<number>();
/** predicateTrait.id -> its registration, for looking up dependencies from the trait. */
const registrationsByPredicateTraitId = new Map<number, PredicateRegistration>();
/** dependency trait.id -> the set of predicate registrations that depend on it. */
const dependentPredicates = new Map<number, Set<PredicateRegistration>>();

export function isPredicateTrait(candidate: Trait): boolean {
    return predicateTraitIds.has(candidate.id);
}

export function isPredicateModifierType(param: unknown): param is PredicateModifier {
    return isModifier(param as Modifier) && (param as Modifier).type.startsWith('predicate-');
}

/**
 * Creates a query modifier that filters entities by evaluating `predicateFn` against the
 * live data of `traits`, instead of by trait presence alone. It can be used as a bare query
 * parameter, or composed with Not/Or/Added/Changed/Removed.
 */
export function createPredicate<T extends Trait[]>(
    traits: [...T],
    predicateFn: (data: unknown[]) => unknown
): PredicateModifier<T> {
    for (const dep of traits) {
        if (isRelation(dep)) {
            throw new Error('Koota: Relations cannot be used as predicate dependencies.');
        }
        if (dep[$internal].type === 'tag') {
            throw new Error('Koota: Tags cannot be used as predicate dependencies.');
        }
    }

    const predicateTrait = trait() as TagTrait;
    predicateTraitIds.add(predicateTrait.id);

    const registration: PredicateRegistration = {
        predicateTrait,
        dependencyTraits: traits as Trait[],
        predicateFn,
    };
    registrationsByPredicateTraitId.set(predicateTrait.id, registration);

    for (const dep of traits) {
        let deps = dependentPredicates.get(dep.id);
        if (!deps) {
            deps = new Set();
            dependentPredicates.set(dep.id, deps);
