    const modifier = createModifier(
        `predicate-${predicateTrait.id}` as const,
        predicateTrait.id,
        traits
    ) as PredicateModifier<T>;
    modifier.predicateTrait = predicateTrait;
    modifier.dependencyTraits = traits;
    modifier.predicateFn = predicateFn;

